// In-memory room store
// Rooms expire after 72h of inactivity (covers full hackathon + sleep)
// Server restart = all rooms lost — MCP tools return explicit error, not silent []

export interface Message {
  id: string;
  from: string;
  ts: number;
  content: string;
}

interface UserState {
  cursor: number; // index of next unread message in room.messages
  lastSeen: number;
}

interface Room {
  code: string;
  messages: Message[];
  users: Map<string, UserState>;
  lastActivity: number;
}

const rooms = new Map<string, Room>();

const MAX_MESSAGE_BYTES = 10 * 1024; // 10KB
const ROOM_TTL_MS = 72 * 60 * 60 * 1000; // 72h

// ── Room management ──────────────────────────────────────────────────────────

export function createRoom(): string {
  const chars = "abcdefghijklmnopqrstuvwxyz0123456789";
  let code: string;
  do {
    code = Array.from(
      { length: 6 },
      () => chars[Math.floor(Math.random() * chars.length)]
    ).join("");
  } while (rooms.has(code));

  rooms.set(code, {
    code,
    messages: [],
    users: new Map(),
    lastActivity: Date.now(),
  });
  return code;
}

export function joinRoom(code: string, name: string): Room | null {
  const room = rooms.get(code);
  if (!room) return null;

  if (!room.users.has(name)) {
    room.users.set(name, { cursor: 0, lastSeen: Date.now() });
  }
  room.lastActivity = Date.now();
  return room;
}

export function getRoomCount(): number {
  return rooms.size;
}

// ── MCP tool operations ───────────────────────────────────────────────────────

type Ok<T> = { ok: true } & T;
type Err = { ok: false; error: string };

export function appendMessage(
  code: string,
  from: string,
  content: string
): Ok<{ id: string }> | Err {
  if (new TextEncoder().encode(content).length > MAX_MESSAGE_BYTES) {
    return { ok: false, error: "message_too_large" };
  }
  const room = rooms.get(code);
  if (!room) return { ok: false, error: "room_expired_server_restarted" };

  const id = crypto.randomUUID();
  room.messages.push({ id, from, ts: Date.now(), content });
  room.lastActivity = Date.now();
  return { ok: true, id };
}

export function getMessages(
  code: string,
  name: string
): Ok<{ messages: Message[] }> | Err {
  const room = rooms.get(code);
  if (!room) return { ok: false, error: "room_expired_server_restarted" };

  const userState = room.users.get(name);
  if (!userState) return { ok: false, error: "not_in_room" };

  // Slice from cursor, filter out own messages, advance cursor
  const messages = room.messages
    .slice(userState.cursor)
    .filter((m) => m.from !== name);
  userState.cursor = room.messages.length;
  userState.lastSeen = Date.now();
  room.lastActivity = Date.now();
  return { ok: true, messages };
}

export function getRoomStatus(
  code: string,
  name: string
): Ok<{ connected: boolean; partners: string[]; message_count: number }> | Err {
  const room = rooms.get(code);
  if (!room) return { ok: false, error: "room_expired_server_restarted" };

  const partners = Array.from(room.users.keys()).filter((u) => u !== name);
  return {
    ok: true,
    connected: partners.length > 0,
    partners,
    message_count: room.messages.length,
  };
}

// ── GC ────────────────────────────────────────────────────────────────────────

export function sweepExpiredRooms(): number {
  const now = Date.now();
  let swept = 0;
  for (const [code, room] of rooms) {
    if (now - room.lastActivity > ROOM_TTL_MS) {
      rooms.delete(code);
      swept++;
    }
  }
  return swept;
}

import { test, expect, beforeEach } from "bun:test";
import {
  createRoom,
  joinRoom,
  appendMessage,
  getMessages,
  getRoomStatus,
  sweepExpiredRooms,
  getRoomCount,
} from "./rooms.js";

// Reset module state between tests by re-importing fresh — not possible with
// static imports, so we rely on unique room codes per test instead.

test("createRoom returns a 6-char code", () => {
  const code = createRoom();
  expect(code).toHaveLength(6);
  expect(code).toMatch(/^[a-z0-9]{6}$/);
});

test("createRoom codes are unique across calls", () => {
  const codes = new Set(Array.from({ length: 20 }, () => createRoom()));
  expect(codes.size).toBe(20);
});

test("joinRoom returns null for unknown room", () => {
  expect(joinRoom("zzzzzz", "alice")).toBeNull();
});

test("joinRoom creates user state on first join", () => {
  const code = createRoom();
  const room = joinRoom(code, "alice");
  expect(room).not.toBeNull();
});

test("appendMessage: happy path", () => {
  const code = createRoom();
  joinRoom(code, "alice");
  const result = appendMessage(code, "alice", "hello");
  expect(result.ok).toBe(true);
  if (result.ok) expect(result.id).toHaveLength(36); // UUID
});

test("appendMessage: rejects messages over 10KB", () => {
  const code = createRoom();
  const big = "x".repeat(10 * 1024 + 1);
  const result = appendMessage(code, "alice", big);
  expect(result.ok).toBe(false);
  if (!result.ok) expect(result.error).toBe("message_too_large");
});

test("appendMessage: unknown room returns room_expired error", () => {
  const result = appendMessage("xxxxxx", "alice", "hi");
  expect(result.ok).toBe(false);
  if (!result.ok) expect(result.error).toBe("room_expired_server_restarted");
});

test("getMessages: returns partner messages after cursor, not own", () => {
  const code = createRoom();
  joinRoom(code, "alice");
  joinRoom(code, "bob");

  appendMessage(code, "alice", "msg from alice");
  appendMessage(code, "bob", "msg from bob");

  const result = getMessages(code, "bob"); // bob reads — should only see alice's
  expect(result.ok).toBe(true);
  if (result.ok) {
    expect(result.messages).toHaveLength(1);
    expect(result.messages[0].from).toBe("alice");
    expect(result.messages[0].content).toBe("msg from alice");
  }
});

test("getMessages: cursor advances — second call returns empty", () => {
  const code = createRoom();
  joinRoom(code, "alice");
  joinRoom(code, "bob");
  appendMessage(code, "alice", "hi");

  getMessages(code, "bob"); // first read
  const second = getMessages(code, "bob"); // second read
  expect(second.ok).toBe(true);
  if (second.ok) expect(second.messages).toHaveLength(0);
});

test("getMessages: empty room returns []", () => {
  const code = createRoom();
  joinRoom(code, "alice");
  const result = getMessages(code, "alice");
  expect(result.ok).toBe(true);
  if (result.ok) expect(result.messages).toHaveLength(0);
});

test("getMessages: unknown room returns room_expired error", () => {
  const result = getMessages("xxxxxx", "alice");
  expect(result.ok).toBe(false);
  if (!result.ok) expect(result.error).toBe("room_expired_server_restarted");
});

test("getMessages: returns messages in timestamp order", () => {
  const code = createRoom();
  joinRoom(code, "alice");
  joinRoom(code, "bob");

  appendMessage(code, "alice", "first");
  appendMessage(code, "alice", "second");
  appendMessage(code, "alice", "third");

  const result = getMessages(code, "bob");
  expect(result.ok).toBe(true);
  if (result.ok) {
    expect(result.messages.map((m) => m.content)).toEqual([
      "first",
      "second",
      "third",
    ]);
  }
});

test("getRoomStatus: solo user shows not connected", () => {
  const code = createRoom();
  joinRoom(code, "alice");
  const result = getRoomStatus(code, "alice");
  expect(result.ok).toBe(true);
  if (result.ok) {
    expect(result.connected).toBe(false);
    expect(result.partners).toHaveLength(0);
  }
});

test("getRoomStatus: two users shows connected with partner", () => {
  const code = createRoom();
  joinRoom(code, "alice");
  joinRoom(code, "bob");
  const result = getRoomStatus(code, "alice");
  expect(result.ok).toBe(true);
  if (result.ok) {
    expect(result.connected).toBe(true);
    expect(result.partners).toContain("bob");
    expect(result.partners).not.toContain("alice");
  }
});

test("getRoomStatus: unknown room returns room_expired error", () => {
  const result = getRoomStatus("xxxxxx", "alice");
  expect(result.ok).toBe(false);
  if (!result.ok) expect(result.error).toBe("room_expired_server_restarted");
});

test("getRoomStatus: includes message_count", () => {
  const code = createRoom();
  joinRoom(code, "alice");
  appendMessage(code, "alice", "a");
  appendMessage(code, "alice", "b");
  const result = getRoomStatus(code, "alice");
  expect(result.ok).toBe(true);
  if (result.ok) expect(result.message_count).toBe(2);
});

test("sweepExpiredRooms: does not delete active rooms", () => {
  const before = getRoomCount();
  createRoom();
  const after = getRoomCount();
  sweepExpiredRooms(); // nothing is expired
  expect(getRoomCount()).toBe(after);
});

/**
 * Walkie-Talkie stdio MCP bridge
 * Calls simple REST endpoints on the walkie-talkie server.
 *
 * Env vars:
 *   SERVER_URL — base URL (default: http://localhost:3001)
 *   ROOM       — room code
 *   NAME       — agent name
 */

import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { CallToolRequestSchema, ListToolsRequestSchema } from "@modelcontextprotocol/sdk/types.js";

const SERVER_URL = process.env.SERVER_URL || "http://localhost:3001";
const ROOM = process.env.ROOM || "";
const NAME = process.env.NAME || "Agent";
const BASE = `${SERVER_URL}/api`;

const mcp = new Server({ name: "walkie-talkie", version: "1.0.0" }, { capabilities: { tools: {} } });

mcp.setRequestHandler(ListToolsRequestSchema, async () => ({
  tools: [
    {
      name: "room_status",
      description: "Check if your partner has joined the room.",
      inputSchema: { type: "object" as const, properties: {} },
    },
    {
      name: "send_to_partner",
      description: "Send a message to your partner's AI.",
      inputSchema: {
        type: "object" as const,
        properties: { message: { type: "string", description: "The message to send" } },
        required: ["message"],
      },
    },
    {
      name: "get_partner_messages",
      description: "Get unread messages from your partner's AI.",
      inputSchema: { type: "object" as const, properties: {} },
    },
  ],
}));

mcp.setRequestHandler(CallToolRequestSchema, async (request) => {
  const { name, arguments: args } = request.params;
  const params = `?room=${ROOM}&name=${NAME}`;

  try {
    if (name === "room_status") {
      const res = await fetch(`${BASE}/status${params}`);
      const data = await res.json();
      return { content: [{ type: "text" as const, text: JSON.stringify(data, null, 2) }] };
    }

    if (name === "get_partner_messages") {
      const res = await fetch(`${BASE}/messages${params}`);
      const data = await res.json() as { ok: boolean; messages?: Array<{from: string; content: string; ts: number}> };
      if (!data.ok || !data.messages?.length) {
        return { content: [{ type: "text" as const, text: "No new messages." }] };
      }
      const formatted = data.messages
        .map((m) => `[${m.from} @ ${new Date(m.ts).toISOString()}]\n${m.content}`)
        .join("\n\n---\n\n");
      return { content: [{ type: "text" as const, text: formatted }] };
    }

    if (name === "send_to_partner") {
      const { message } = args as { message: string };
      const res = await fetch(`${BASE}/send${params}`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ message }),
      });
      const data = await res.json();
      return { content: [{ type: "text" as const, text: data.ok ? `Sent ✓ (id: ${data.id})` : `Error: ${data.error}` }] };
    }

    return { content: [{ type: "text" as const, text: `Unknown tool: ${name}` }] };
  } catch (e: unknown) {
    return { content: [{ type: "text" as const, text: `Error: ${e instanceof Error ? e.message : String(e)}` }] };
  }
});

const transport = new StdioServerTransport();
await mcp.connect(transport);

